// Per-instance sampling state. Each Avo instance owns one of these and passes
// it to AvoInvoke.invoke / invokeMeta. The server's response (data.sa) mutates
// state.rate so the next call's sampling decision uses the latest server value.
export interface AvoSamplingState {
  rate: number;
}

// AvoInvoke: config-parameterized invocation metrics.
// invoke() and invokeMeta() accept an AvoInvokeConfig so the caller
// supplies IDs at runtime rather than having them hardcoded here.
// Mirrors AvoSwift.res printInvocationFunctionWithConfig.
export const AvoInvoke = {
  invoke(eventId: string, eventHash: string, violations: AvoAssertMessage[], config: AvoInvokeConfig, samplingState: AvoSamplingState): void {
    if (samplingState.rate <= 0) { return; }
    if (Math.random() >= samplingState.rate) { return; }
    try {
      fetch("https://api.avo.app/i", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          "ac": config.actionId,
          "br": config.branchId,
          "sc": config.schemaId,
          "so": config.sourceId,
          "en": config.env,
          "ev": eventId,
          "ha": eventHash,
          "se": (new Date()).toISOString(),
          "va": violations.length === 0,
          "me": violations,
          "or": "library-interface"
        })
      }).then((res: any) => res.json()).then((data: any) => {
        const nextSamplingRate = data?.sa;
        if (typeof nextSamplingRate === "number" && Number.isFinite(nextSamplingRate) && nextSamplingRate >= 0 && nextSamplingRate <= 1) {
          samplingState.rate = nextSamplingRate;
        }
      }).catch(() => {});
    } catch (_e) {}
  },

  invokeMeta(type: string, messages: AvoAssertMessage[], config: AvoInvokeConfig, samplingState: AvoSamplingState): void {
    if (samplingState.rate <= 0) { return; }
    if (Math.random() >= samplingState.rate) { return; }
    try {
      fetch("https://api.avo.app/i", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          "ac": config.actionId,
          "br": config.branchId,
          "sc": config.schemaId,
          "so": config.sourceId,
          "en": config.env,
          "ty": type,
          "se": (new Date()).toISOString(),
          "va": messages.length === 0,
          "me": messages,
          "or": "library-interface"
        })
      }).then((res: any) => res.json()).then((data: any) => {
        const nextSamplingRate = data?.sa;
        if (typeof nextSamplingRate === "number" && Number.isFinite(nextSamplingRate) && nextSamplingRate >= 0 && nextSamplingRate <= 1) {
          samplingState.rate = nextSamplingRate;
        }
      }).catch(() => {});
    } catch (_e) {}
  },
};

