export class AvoVerificationError extends Error {
  public readonly messages: string[];
  constructor(messages: string[]) {
    super(messages.join("; "));
    // Restore prototype chain immediately after super() — required for correct instanceof checks
    // when TypeScript targets ES5 (transpiled classes lose the prototype chain otherwise).
    Object.setPrototypeOf(this, AvoVerificationError.prototype);
    this.name = "AvoVerificationError";
    this.messages = messages;
    // Capture a clean stack trace when V8 is available (Node.js / Chrome).
    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, AvoVerificationError);
    }
  }
}

// BaseAvoEvent: abstract class providing default implementations for AvoEvent.
// This is the TypeScript analog of Swift's protocol extension defaults.
// Concrete event classes extend BaseAvoEvent and override what they need.
export abstract class BaseAvoEvent implements AvoEvent {
  abstract readonly eventId: string;
  abstract readonly eventHash: string;
  abstract readonly eventName: string;
  abstract readonly properties: Record<string, AvoDestinationEvent>;
  abstract buildBaseProperties(): Record<string, unknown>;

  get canonicalProperties(): Record<string, unknown> {
    return this.buildBaseProperties();
  }

  collectViolations(): AvoAssertMessage[] {
    return [];
  }

  /** runValidation() is what track() calls. Override in subclasses to add pre-checks
   *  (e.g. AppSystemProperties.isConfigured) before collectViolations() runs.
   *  The default implementation just returns collectViolations(). */
  runValidation(): AvoAssertMessage[] {
    return this.collectViolations();
  }

  verify(): void {
    const messages = this.runValidation();
    if (messages.length > 0) {
      throw new AvoVerificationError(messages.map(v => v.getMessage()));
    }
  }
}

// The Avo runtime class. Plan-agnostic — all plan-specific data (invokeConfig, required
// destination keys, per-destination api keys) flows in via the AvoCodegenConfig argument
// to init(). One Avo instance per app — multi-app shells construct multiple instances
// and each owns its own samplingState (no module-global sampling state).
export class Avo {
  private readonly env: AvoEnv;
  private readonly strict: boolean;
  private readonly noop: boolean;
  private readonly inspector?: AvoInspector | null;
  private readonly destinations: Record<string, AvoDestination>;
  private readonly invokeConfig: AvoInvokeConfig;
  // Per-instance sampling state — mutated by AvoInvoke based on server response.
  // Each Avo.init() returns a separate instance with its own state, so multi-app
  // shells do not share a single sampling decision across plans.
  private readonly samplingState: AvoSamplingState = { rate: 1.0 };

  private constructor(config: AvoConfig, invokeConfig: AvoInvokeConfig, resolvedDestinations: Record<string, AvoDestination>) {
    this.env = config.env;
    this.strict = config.strict ?? false;
    this.noop = config.noop ?? false;
    this.inspector = config.inspector;
    this.destinations = resolvedDestinations;
    this.invokeConfig = invokeConfig;

    // Part B: noop warn — TS deliberately does NOT force noop=false in prod (diverges from Swift)
    if (config.noop === true) {
      console.warn("[avo] noop mode is active — all track() calls will be no-ops.");
    }
    if (!this.noop && this.env !== AvoEnv.Prod) {
      AvoInvoke.invokeMeta("init", [], this.invokeConfig, this.samplingState);
    }
  }

  // init resolves destinations against the codegen-bound requiredDestinationKeys list,
  // then calls make() on each resolved destination, then constructs the Avo instance.
  // Resolution policy:
  //   Branch (1) zero-destination plan      → resolved = {}, no fan-out
  //   Branch (2) no destinations provided   → resolved = {}, no fan-out (matches Swift/Kotlin process())
  //   Branch (3) partial destinations       → throw (all-or-nothing)
  //   Branch (4) full destinations          → resolved = provided
  static init(config: AvoConfig, codegenConfig: AvoCodegenConfig): Avo {
    const required = codegenConfig.requiredDestinationKeys;
    const provided = config.destinations ?? {};
    const providedKeys = Object.keys(provided);

    let resolved: Record<string, AvoDestination>;

    if (required.length === 0) {
      // Branch (1): zero-destination plan. Resolved is empty regardless of what was provided.
      resolved = {};
    } else if (providedKeys.length === 0) {
      // Branch (2): no destinations provided — opt out of internal fan-out.
      // track() still returns the per-destination payload map; caller fans out.
      resolved = {};
    } else if (providedKeys.length < required.length) {
      // Branch (3): partial. Caller probably forgot to add a destination after pulling. Fail fast.
      const missing = required.filter(k => !(k in provided));
      throw new Error(
        `[avo] Avo.init: custom destinations must cover all DestinationKeys (all-or-nothing). Missing: [${missing.join(", ")}]. Provide implementations for all DestinationKeys.`
      );
    } else {
      // Branch (4): full custom destinations.
      const missing = required.filter(k => !(k in provided));
      if (missing.length > 0) {
        throw new Error(
          `[avo] Avo.init: custom destinations must cover all DestinationKeys (all-or-nothing). Missing: [${missing.join(", ")}]. Provide implementations for all DestinationKeys.`
        );
      }
      resolved = provided as Record<string, AvoDestination>;
    }

    // Call make() on each resolved destination. Skip the loop when resolved is empty
    // (zero-destination plan or opted-out caller). Per-destination try/catch ensures
    // one misbehaving destination does not prevent others from initializing.
    for (const [key, dest] of Object.entries(resolved)) {
      try {
        const keys = codegenConfig.destinationApiKeys[key];
        const apiKey = keys
          ? (config.env === AvoEnv.Prod ? keys.prod : config.env === AvoEnv.Staging ? (keys.staging ?? keys.dev) : keys.dev)
          : undefined;
        dest.make(config.env, apiKey ?? undefined);
      } catch (e) {
        console.warn("[avo] Destination " + key + " make() threw, continuing", e);
      }
    }

    // Merge env into invokeConfig at runtime so invocation metrics carry the environment dimension.
    const invokeConfig = { ...codegenConfig.invokeConfig, env: config.env };
    return new Avo(config, invokeConfig, resolved);
  }

  // track returns the per-destination payload map (event.properties). Callers may use
  // the return value to fan out manually to their own SDKs (Swift/Kotlin process()
  // semantics). When this.destinations is non-empty the lib also fans out internally
  // by calling each dest.logEvent — both behaviors layer cleanly.
  track(event: AvoEvent): Record<string, AvoDestinationEvent> {
    if (this.noop) { return event.properties; }

    // Call runValidation() instead of collectViolations() directly so that per-event
    // overrides (e.g. the AppSystemProperties.isConfigured pre-check) run in the
    // production tracking path — not just when verify() is called explicitly.
    let violations: AvoAssertMessage[];
    try {
      violations = event.runValidation();
    } catch (e) {
      if (e instanceof AvoVerificationError) {
        if (this.env !== AvoEnv.Prod && this.strict) {
          throw e;
        } else {
          for (const msg of e.messages) {
            console.error("[avo] Pre-validation check failed: " + msg);
          }
        }
        return event.properties; // do not fan-out when pre-validation throws, but still return the map
      }
      throw e;
    }
    if (this.env !== AvoEnv.Prod) {
      AvoInvoke.invoke(event.eventId, event.eventHash, violations, this.invokeConfig, this.samplingState);
    }

    if (violations.length > 0) {
      if (this.env !== AvoEnv.Prod && this.strict) {
        throw new AvoVerificationError(violations.map(v => v.getMessage()));
      } else {
        for (const v of violations) {
          console.error("[avo] Verification failed: " + v.getMessage());
        }
        // continue to inspector + fan-out
      }
    }

    if (this.inspector != null) {
      try {
        const inspectorProperties: Record<string, unknown> = { ...event.canonicalProperties };
        inspectorProperties["avoFunctionEventId"] = event.eventId;
        inspectorProperties["avoFunctionEventHash"] = event.eventHash;
        this.inspector.avoFunctionTrackSchemaFromEvent(event.eventName, inspectorProperties);
      } catch (e) {
        console.error("[avo] Inspector call failed: " + e);
      }
    }

    // Internal fan-out — only when destinations is non-empty. Caller can opt out by
    // omitting destinations from config; track() return value still carries the map
    // so the caller can fan out manually.
    if (Object.keys(this.destinations).length > 0) {
      for (const [key, dest] of Object.entries(this.destinations)) {
        const payload = (event.properties as Record<string, AvoDestinationEvent>)[key];
        if (payload) {
          try {
            dest.logEvent({
              name: payload.name,
              properties: payload.properties,
              eventId: event.eventId,
              eventHash: event.eventHash,
              eventName: event.eventName,
            });
          } catch (e) { console.warn("[avo] Destination " + key + " logEvent threw, continuing", e); }
        }
      }
    }

    return event.properties;
  }

  // setUserProperties is a no-op when destinations is empty. Callers in no-destinations
  // mode call their own SDKs' identify/setUserProperties directly. No payload-map return —
  // user properties are flat (no per-destination payload structure).
  setUserProperties(userId: string, properties: Record<string, unknown>): void {
    if (this.noop) { return; }
    if (Object.keys(this.destinations).length === 0) { return; }
    for (const [key, dest] of Object.entries(this.destinations)) {
      try {
        dest.setUserProperties(userId, { ...properties });
      } catch (e) {
        console.warn("[avo] Destination " + key + " setUserProperties threw, continuing", e);
      }
    }
  }
}
